import{_ as c,C as l,o as d,c as m,a2 as a,b as o,w as t,a as s,E as i,a3 as n}from"./chunks/framework._O8Cueap.js";const A=JSON.parse('{"title":"Admin","description":"","frontmatter":{},"headers":[],"relativePath":"concepts/admin.md","filePath":"concepts/admin.md"}'),g={name:"concepts/admin.md"};function h(u,e,p,b,f,v){const r=l("Mermaid");return d(),m("div",null,[e[2]||(e[2]=a('<h1 id="admin" tabindex="-1">Admin <a class="header-anchor" href="#admin" aria-label="Permalink to &quot;Admin&quot;">​</a></h1><p>Workspace administrators have access to management features for models, users, rate limits, and security.</p><h2 id="admin-pages" tabindex="-1">Admin Pages <a class="header-anchor" href="#admin-pages" aria-label="Permalink to &quot;Admin Pages&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Page</th><th>Path</th><th>Description</th></tr></thead><tbody><tr><td>Users</td><td><code>/{workspace}/admin/users</code></td><td>List, add, and manage user roles</td></tr><tr><td>Models</td><td><code>/{workspace}/admin/models</code></td><td>Configure available AI models and credit costs</td></tr><tr><td>Auth Providers</td><td><code>/{workspace}/admin/auth-providers</code></td><td>Configure authentication providers (Database, LDAP). See <a href="/open-agent-orchestra/concepts/auth-providers.html">Auth Providers</a></td></tr><tr><td>Rate Limits</td><td><code>/{workspace}/admin/rate-limits</code></td><td>Set workspace defaults and per-user credit limits</td></tr><tr><td>Security</td><td><code>/{workspace}/admin/security</code></td><td>Configure workspace self-service registration and forgot-password access</td></tr><tr><td>Mail Settings</td><td><code>/{workspace}/admin/mail-settings</code></td><td>Configure global SMTP settings for password reset and system emails (<code>super_admin</code> only)</td></tr><tr><td>Workspaces</td><td><code>/{workspace}/workspaces</code></td><td>Manage workspaces (<code>super_admin</code> only)</td></tr></tbody></table><h2 id="model-management" tabindex="-1">Model Management <a class="header-anchor" href="#model-management" aria-label="Permalink to &quot;Model Management&quot;">​</a></h2><p>Admins configure which AI models are available in the workspace. Each model has:</p><table tabindex="0"><thead><tr><th>Field</th><th>Description</th></tr></thead><tbody><tr><td><strong>Name</strong></td><td>Model identifier (e.g., <code>gpt-5.4</code>, <code>claude-sonnet-4-6</code>)</td></tr><tr><td><strong>Provider</strong></td><td>Provider name (default: <code>github</code>)</td></tr><tr><td><strong>Credit Cost</strong></td><td>Credits consumed per session (default: 1.00)</td></tr><tr><td><strong>Active</strong></td><td>Whether the model is available for use</td></tr></tbody></table><p>Active model records power the authenticated model selectors used by conversations and other runtime configuration screens. If a model is deactivated or removed, turn settings fall back to the current workspace default instead of continuing to show a phantom hard-coded model name.</p><p>Default models created by the seed script:</p><table tabindex="0"><thead><tr><th>Model</th><th>Provider</th><th>Credit Cost</th></tr></thead><tbody><tr><td><code>claude-sonnet-4-6</code></td><td>Anthropic</td><td>1.00</td></tr><tr><td><code>claude-opus-4-6</code></td><td>Anthropic</td><td>1.00</td></tr><tr><td><code>gpt-5.4</code></td><td>OpenAI</td><td>1.00</td></tr><tr><td><code>gpt-5-mini</code></td><td>OpenAI</td><td>1.00</td></tr></tbody></table><h2 id="rate-limit-system" tabindex="-1">Rate Limit System <a class="header-anchor" href="#rate-limit-system" aria-label="Permalink to &quot;Rate Limit System&quot;">​</a></h2>',11)),(d(),o(n,null,{default:t(()=>[i(r,{id:"mermaid-225",class:"mermaid",graph:"graph%20TB%0A%20%20%20%20WQ%5BWorkspace%20Rate%20Limits%3Cbr%2F%3Edaily%20%2B%20weekly%20%2B%20monthly%20defaults%5D%20--%3E%7Cdefault%20for%7C%20UQ%5BUser%20Rate%20Limits%3Cbr%2F%3Eper-user%20overrides%5D%0A%20%20%20%20UQ%20--%3E%7Cchecked%20before%7C%20EXEC%5BStep%20Execution%5D%0A%20%20%20%20EXEC%20--%3E%7Cconsumed%7C%20CU%5BCredit%20Usage%3Cbr%2F%3Eper%20user%20%2F%20model%20%2F%20day%20%2F%20cost%20snapshot%5D%0A%0A%20%20%20%20style%20WQ%20fill%3A%23FF9800%2Ccolor%3A%23fff%0A%20%20%20%20style%20UQ%20fill%3A%232196F3%2Ccolor%3A%23fff%0A"})]),fallback:t(()=>[...e[0]||(e[0]=[s(" Loading... ",-1)])]),_:1})),e[3]||(e[3]=a('<div class="mermaid-source" data-mermaid-source=""></div><ul><li><strong>Workspace defaults</strong> — Daily, weekly, and monthly credit limits for users who do not override them</li><li><strong>User overrides</strong> — Per-user limits that take precedence over workspace defaults</li><li><strong>Credit tracking</strong> — Tracked in <code>credit_usage</code> with the model credit cost snapshot captured at execution time</li><li><strong>Historical stability</strong> — Updating a model&#39;s current credit cost does not retroactively change prior usage totals</li></ul><h2 id="user-management" tabindex="-1">User Management <a class="header-anchor" href="#user-management" aria-label="Permalink to &quot;User Management&quot;">​</a></h2>',3)),(d(),o(n,null,{default:t(()=>[i(r,{id:"mermaid-252",class:"mermaid",graph:"graph%20LR%0A%20%20%20%20REG%5BUser%20Registers%3Cbr%2F%3Eas%20creator_user%5D%20--%3E%20ADMIN%5BAdmin%20Changes%20Role%5D%0A%20%20%20%20ADMIN%20--%3E%20WA%5Bworkspace_admin%5D%0A%20%20%20%20ADMIN%20--%3E%20VU%5Bview_user%5D%0A%20%20%20%20ADMIN%20--%3E%20CU%5Bcreator_user%5D%0A"})]),fallback:t(()=>[...e[1]||(e[1]=[s(" Loading... ",-1)])]),_:1})),e[4]||(e[4]=a('<div class="mermaid-source" data-mermaid-source="Z3JhcGggTFIKICAgIFJFR1tVc2VyIFJlZ2lzdGVyczxici8+YXMgY3JlYXRvcl91c2VyXSAtLT4gQURNSU5bQWRtaW4gQ2hhbmdlcyBSb2xlXQogICAgQURNSU4gLS0+IFdBW3dvcmtzcGFjZV9hZG1pbl0KICAgIEFETUlOIC0tPiBWVVt2aWV3X3VzZXJdCiAgICBBRE1JTiAtLT4gQ1VbY3JlYXRvcl91c2VyXQ=="></div><ul><li>New users register as <code>creator_user</code> by default</li><li>Admins can promote/demote users via <strong>Admin → Users</strong></li><li><code>super_admin</code> can move users between workspaces</li></ul><h2 id="workspace-security" tabindex="-1">Workspace Security <a class="header-anchor" href="#workspace-security" aria-label="Permalink to &quot;Workspace Security&quot;">​</a></h2><p>The <strong>Admin → Security</strong> page controls self-service account features at the workspace boundary:</p><table tabindex="0"><thead><tr><th>Setting</th><th>Effect</th></tr></thead><tbody><tr><td>Allow User Registration</td><td>Shows the registration link on the login page and allows <code>POST /api/auth/register</code> for the workspace</td></tr><tr><td>Allow Forgot Password</td><td>Shows the forgot-password link for database users and allows password reset email requests</td></tr></tbody></table><p>Both settings are stored on the workspace record. Existing authenticated users can still sign in when registration is disabled, and LDAP users continue to manage passwords through their external directory.</p><h2 id="mail-settings" tabindex="-1">Mail Settings <a class="header-anchor" href="#mail-settings" aria-label="Permalink to &quot;Mail Settings&quot;">​</a></h2><p>The <strong>Admin → Mail Settings</strong> page is available to <code>super_admin</code> users and stores the platform SMTP configuration. Forgot-password email delivery uses this configuration; if SMTP is not configured, reset requests are accepted but no email is sent.</p><h2 id="system-events" tabindex="-1">System Events <a class="header-anchor" href="#system-events" aria-label="Permalink to &quot;System Events&quot;">​</a></h2><p>The platform logs 21 system event types accessible via <strong>Events</strong> page:</p><table tabindex="0"><thead><tr><th>Category</th><th>Events</th></tr></thead><tbody><tr><td>Agent</td><td><code>agent.created</code>, <code>agent.updated</code>, <code>agent.deleted</code>, <code>agent.status_changed</code></td></tr><tr><td>Workflow</td><td><code>workflow.created</code>, <code>workflow.updated</code>, <code>workflow.deleted</code></td></tr><tr><td>Execution</td><td><code>execution.started</code>, <code>execution.completed</code>, <code>execution.failed</code>, <code>execution.cancelled</code></td></tr><tr><td>Step</td><td><code>step.completed</code>, <code>step.failed</code></td></tr><tr><td>Trigger</td><td><code>trigger.fired</code></td></tr><tr><td>User</td><td><code>user.login</code>, <code>user.registered</code></td></tr><tr><td>Variable</td><td><code>variable.created</code>, <code>variable.updated</code>, <code>variable.deleted</code></td></tr></tbody></table><p>Events can be used to trigger workflows via <a href="/open-agent-orchestra/concepts/workflows.html#event-trigger">event triggers</a>.</p><h2 id="supervisor-controls" tabindex="-1">Supervisor Controls <a class="header-anchor" href="#supervisor-controls" aria-label="Permalink to &quot;Supervisor Controls&quot;">​</a></h2><p>Emergency controls for administrators:</p><table tabindex="0"><thead><tr><th>Endpoint</th><th>Description</th></tr></thead><tbody><tr><td><code>POST /api/supervisor/emergency-stop</code></td><td>Pause all active agents</td></tr><tr><td><code>POST /api/supervisor/resume-all</code></td><td>Resume all paused agents</td></tr><tr><td><code>GET /api/supervisor/status</code></td><td>System-wide supervisor status</td></tr></tbody></table>',15))])}const k=c(g,[["render",h]]);export{A as __pageData,k as default};
